-- PostgreSQL demo seed for GA4 commerce + LoopAd intervention data.
-- Keep this file aligned with clickhouse/ga4_exports/*.csv.

BEGIN;

DELETE FROM projects WHERE id = 'google-ga4-demo-commerce';


























ON CONFLICT (action_id) DO UPDATE SET
    action_type = EXCLUDED.action_type,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    target_step = EXCLUDED.target_step,
    primary_metric = EXCLUDED.primary_metric,
    expected_impact = EXCLUDED.expected_impact,
    execution_hint_json = EXCLUDED.execution_hint_json,
    status = EXCLUDED.status;

ON CONFLICT (project_id) DO UPDATE SET enabled = EXCLUDED.enabled, auto_execute_enabled = EXCLUDED.auto_execute_enabled, allowed_action_ids = EXCLUDED.allowed_action_ids;









-- Keep BIGSERIAL sequences ahead of explicit demo ids.
SELECT setval(pg_get_serial_sequence('experiments', 'id'), COALESCE((SELECT MAX(id) FROM experiments), 1), true);
SELECT setval(pg_get_serial_sequence('segment_ad_mappings', 'id'), COALESCE((SELECT MAX(id) FROM segment_ad_mappings), 1), true);
SELECT setval(pg_get_serial_sequence('ad_creatives', 'id'), COALESCE((SELECT MAX(id) FROM ad_creatives), 1), true);
SELECT setval(pg_get_serial_sequence('bandit_policies', 'id'), COALESCE((SELECT MAX(id) FROM bandit_policies), 1), true);
SELECT setval(pg_get_serial_sequence('bandit_arms', 'id'), COALESCE((SELECT MAX(id) FROM bandit_arms), 1), true);
SELECT setval(pg_get_serial_sequence('bandit_decisions', 'id'), COALESCE((SELECT MAX(id) FROM bandit_decisions), 1), true);
SELECT setval(pg_get_serial_sequence('campaigns', 'id'), COALESCE((SELECT MAX(id) FROM campaigns), 1), true);
SELECT setval(pg_get_serial_sequence('coupons', 'id'), COALESCE((SELECT MAX(id) FROM coupons), 1), true);
SELECT setval(pg_get_serial_sequence('recommendation_results', 'id'), COALESCE((SELECT MAX(id) FROM recommendation_results), 1), true);
SELECT setval(pg_get_serial_sequence('recommendation_actions', 'id'), COALESCE((SELECT MAX(id) FROM recommendation_actions), 1), true);
SELECT setval(pg_get_serial_sequence('dashboard_users', 'id'), COALESCE((SELECT MAX(id) FROM dashboard_users), 1), true);
SELECT setval(pg_get_serial_sequence('user_profiles', 'id'), COALESCE((SELECT MAX(id) FROM user_profiles), 1), true);
SELECT setval(pg_get_serial_sequence('segments', 'id'), COALESCE((SELECT MAX(id) FROM segments), 1), true);

COMMIT;
